Title: node 16.x does not raise error on write when server closes connection

Body:
### Node version and platform

``` bash
$ node -v
v16.0.0
$ uname -a
Darwin Troelss-Mac-mini.local 20.4.0 Darwin Kernel Version 20.4.0: Thu Apr 22 21:46:41 PDT 2021; root:xnu-7195.101.2~1/RELEASE_ARM64_T8101 arm64
```

### What steps will reproduce the bug?

``` javascript
let os = require('os')
let net = require('net')
let crypto = require('crypto')

let socketPath = `${os.tmpdir()}/${crypto.randomBytes(12).toString('hex')}.sock`

let server = net.createServer(socket => {
    let buffer = Buffer.alloc(0)
    socket.on('data', chunk => {
        if(chunk.toString('utf8') === 'destroy') {
            console.log('server destroy')
            socket.destroy()
        }       
    })
})
server.on('listening', () => {
    // client closes
    const socket1 = net.connect({ path: socketPath })
    socket1.on('error', (e) => {
        console.log('socket1:' + e.toString())
    })
    socket1.end()
    socket1.write('hello')

    // server closes
    const socket2 = net.connect({ path: socketPath })
    socket2.on('error', (e) => {
        console.log('socket2:' + e.toString())
    })
    socket2.write('destroy')
    setTimeout(() => {
        socket2.write()
    }, 1000)
})
server.listen(socketPath)
```

### How often does it reproduce? Is there a required condition?

Every time.

### What is the expected behavior?

Node 12.x:

``` bash
$ /opt/homebrew/Cellar/node@12/12.22.1_1/bin/node socket-errors.js
socket1:Error [ERR_STREAM_WRITE_AFTER_END]: write after end
server destroy
socket2:Error: This socket has been ended by the other party
```

Node 14.x:

``` bash
$ /opt/homebrew/Cellar/node@14/14.17.0/bin/node socket-errors.js 
socket1:Error [ERR_STREAM_WRITE_AFTER_END]: write after end
server destroy
socket2:Error: This socket has been ended by the other party
```

### What do you see instead?

Node 16.x:

``` bash
$ /opt/homebrew/Cellar/node/16.0.0_1/bin/node socket-errors.js 
socket1:Error [ERR_STREAM_WRITE_AFTER_END]: write after end
server destroy
```

### Additional information

<!--
Tell us anything else you think we should know.
-->

body:
**Is your feature request related to a problem? Please describe.**

In this example there is thrown error during `for await` but stream ends with premature close error instead of thrown error. If `Promise.allSettled` was changed to `Promise.all` then it would be undefined which error it gets whether `error abc` or premature close.

``` js
let { finished } = require("stream/promises");
let fs = require("fs");

fs.writeFileSync("file", Buffer.alloc(1000000));

(async function()
{
	let stream = require("fs").createReadStream("file");
	let func = async function()
	{
		for await (let _ of stream) throw new Error("abc");
	};
	let res = await Promise.allSettled([finished(stream), func()]);
	console.log(res);
}());
```

Possible output:
```
[
  {
    status: 'rejected',
    reason: Error [ERR_STREAM_PREMATURE_CLOSE]: Premature close
    ...
  },
  {
    status: 'rejected',
    reason: Error: abc
    ...
  }
]
```

**Describe the solution you'd like**

It would be better if it caused `error abc` also on source stream so `Promise.all` would return this error consistently.

**Describe alternatives you've considered**

Currently one must for example destroy source stream with `error abc` instead of throw in `for await` to achieve desired result:

``` js
let { finished } = require("stream/promises");
let fs = require("fs");

fs.writeFileSync("file", Buffer.alloc(1000000));

(async function()
{
	let stream = require("fs").createReadStream("file");
	let func = async function()
	{
		for await (let _ of stream) stream.destroy(new Error("abc"));
	};
	let res = await Promise.allSettled([finished(stream), func()]);
	console.log(res);
}());
```
```
[
  {
    status: 'rejected',
    reason: Error: abc
  },
  {
    status: 'rejected',
    reason: Error: abc
  }
]
```

