async function main() {
    const fileStream = fs.createReadStream('input.txt');
    let lineReader = readline.createInterface({
        input: fileStream,
        crlfDelay: Infinity,
    });
    console.log("Enter sleep");
    await sleep(1000);
    console.log("Exit sleep");

    for await (const line of lineReader) {
        console.log("line: " + line);
    }
    console.log("DONE");
}

main();
```

### How often does it reproduce? Is there a required condition?

Always.

### What is the expected behavior?

The program should sleep for a second, then read all lines of `input.txt`, before printing `DONE`.

### What do you see instead?

The program outputs only:
```
Enter sleep
Exit sleep
```
And terminates without any error. It does not print `DONE`.

### Additional information

This stackoverflow answer adds some useful debugging information: for example that the bug does not happen if we pause the stream while sleeping, or if we sleep before opening the stream instead of after.

https://stackoverflow.com/a/71589103/7492244

body:
### What is the problem this feature will solve?

Allows to conform to spec

https://developer.mozilla.org/en-US/docs/Web/API/Blob/type

### What is the feature you are proposing to solve the problem?

Add params: `streamConsumers.blob(stream:Readable, options?: BlobPropertyBag)`

### What alternatives have you considered?

Either wrap in a Proxy:

````js
if (streamConsumers.blob) {
  const result = await streamConsumers.blob(this.stream);
  this.#bodyUsed = true;
  return new Proxy(result, {
    get: (target, p, receiver) => {
      if (p === 'type') return this.headers['content-type'];
      return Reflect.get(target, p, receiver);
    },
  });
}
````

Or hijack the prototype to create a new `Blob`

````js
if (streamConsumers.blob) {
  const generator = function* generator() {};
  const emptyBlob = await streamConsumers.blob(Readable.from(generator()));
  Blob = Object.getPrototypeOf(emptyBlob).constructor;
}

/* ... */

const chunks = [];
for await (const chunk of this.stream) { chunks.push(chunk); }
this.#bodyUsed = true;
return new Blob(chunks, {
  type: this.headers['content-type'],
});
````

