  }
}

// comment either one to see the actual flow
// fire end once when using pipe
new CustomReadable("pipe").pipe(new CustomWritable("pipe"));
// fire end twice when using pipeline
await pipeline(new CustomReadable("pipeline"), new CustomWritable("pipeline"));
```

### How often does it reproduce? Is there a required condition?

Always.

### What is the expected behavior?

`.end` should not call twice and behave similar to `pipe`.

```js
// pipeline
pipeline: write hello world
pipeline: end readable
pipeline: fire write
pipeline: fire end

// pipe
pipe: write hello world
pipe: end readable
pipe: fire write
pipe: fire end
```

### What do you see instead?

`.end` being called twice when using `pipeline`.
```js
// pipeline
pipeline: write hello world
pipeline: end readable
pipeline: fire write
pipeline: fire end
pipeline: fire end

// pipe
pipe: write hello world
pipe: end readable
pipe: fire write
pipe: fire end
```

### Additional information

It is currently affecting [`mongodb`](https://github.com/mongodb/node-mongodb-native/blob/f423e1f22e3a762082ca31de7df1495d01641254/src/gridfs/upload.ts#L175-L219) usage in `node@18`. I assume it is bug from core but not their side.
If it is the expected behavior, I will try to fix it on `mongodb` side.

```js
import { pipeline } from 'stream/promises'
import fs from 'fs'

const { MongoClient, GridFSBucket } = require('mongodb');

const client = await MongoClient.connect(`mongodb://localhost:27017`);

const database = client.db('test01');
const bucket = new GridFSBucket(database, { bucketName: 'test01' });

const readable = fs.createReadStream('/tmp/test.txt');
const writable = bucket.openUploadStream('test.txt')
await pipeline(readable, writable)
```

body:
### What is the problem this feature will solve?

While working on the `url-state-machine` (https://github.com/anonrig/url-js), I realized that Node.js/JavaScript lacks the function of casting an array of ASCII numbers to an integer.

<img width="732" alt="raycast-untitled-3" src="https://user-images.githubusercontent.com/1935246/165185479-cd88c310-38d3-43cf-ac26-2ded36ccd7da.png">

## JavaScript solution (Number.fromCharCode)

```javascript
function fromCharCode(array, radix) {
  return parseInt(String.fromCharCode(...array), radix)
}
```

## Node.js Solution

```javascript
const assert = require('node:assert/strict');
const { numberFromCharCode } = require('node:util');
assert(numberFromCharCode([49, 50, 51], 10), 123);
```

### What is the feature you are proposing to solve the problem?

Adding `Number.fromCharCode(array, radix)` under Number, and supporting this within Node.js.

### What alternatives have you considered?

Making a proposal to JavaScript TSC.

To build and run Node.js as a minimal JavaScript runtime, with specific requirements that will not change: `process`, `Buffer`, `Array`, `JSON`, `require('child_process')`

protocol.js from https://github.com/simov/native-messaging/blob/master/protocol.js

```
module.exports = (handleMessage) => {

  process.stdin.on('readable', () => {
    var input = []
    var chunk
    while (chunk = process.stdin.read()) {
      input.push(chunk)
    }
    input = Buffer.concat(input)

    var msgLen = input.readUInt32LE(0)
    var dataLen = msgLen + 4

    if (input.length >= dataLen) {
      var content = input.slice(4, dataLen)
      var json = JSON.parse(content.toString())
      handleMessage(json)
    }
  })

  function sendMessage (msg) {
    var buffer = Buffer.from(JSON.stringify(msg))

    var header = Buffer.alloc(4)
    header.writeUInt32LE(buffer.length, 0)

    var data = Buffer.concat([header, buffer])
    process.stdout.write(data)
  }

  process.on('uncaughtException', (err) => {
    sendMessage({error: err.toString()})
  })

  return sendMessage

}
```

example.js

```
#!/home/user/node

// Might be good to use an explicit path to node on the shebang line
// in case it isn't in PATH when launched by Chrome

var sendMessage = require('./protocol')(handleMessage)

function handleMessage (req) {
  if (req.message === 'ping') {
    sendMessage({message: 'pong', body: `hello from nodejs ${process.version} app`})
  }

  if (req.message === 'write') {
    var {exec} = require("child_process");
    exec(req.body, (err, stdout, stderr) => {
      if (err) {
        // node couldn't execute the command
        sendMessage({message: "stderr", body: err});
        return;
      }
      sendMessage({message: "output", body: stdout});   
    });    
  }

}
```

I read https://github.com/nodejs/node/issues/2948 and  https://github.com/nodejs/docs/issues/88.

This is what I have tried

```
$ ./configure --dest-cpu=x86_64 \
 --dest-os=linux \  
 --no-cross-compiling \
 --fully-static \ 
 --without-intl \ 
 --without-node-code-cache \
 --without-npm \
 --without-ssl \
 --without-node-snapshot \
 --without-dtrace \
 --without-etw \
 --without-inspector \
 --without-corepack
```

I did not locate an official, formal procedure to build minimal `node`.

Ideally, given existing files which contain the complete code required `node` executable can be build targeting only the dependencies in the existing .js files, adding nothing else, e.g., no `npm`, `WebAssembly`, SSL, etc. 

Currently the nightly `node` executable is ~80MB. I suspect the executable can be built less expensively, without including source code that will not be used in the resulting `node` executable. 

Kindly share the official procedure to build minimal `node` executable.

text:
Title: Minimal build

Body:
To build and run Node.js as a minimal JavaScript runtime, with specific requirements that will not change: `process`, `Buffer`, `Array`, `JSON`, `require('child_process')`

protocol.js from https://github.com/simov/native-messaging/blob/master/protocol.js

```
module.exports = (handleMessage) => {

  process.stdin.on('readable', () => {
    var input = []
    var chunk
    while (chunk = process.stdin.read()) {
      input.push(chunk)
    }
    input = Buffer.concat(input)

    var msgLen = input.readUInt32LE(0)
    var dataLen = msgLen + 4

    if (input.length >= dataLen) {
      var content = input.slice(4, dataLen)
      var json = JSON.parse(content.toString())
      handleMessage(json)
    }
  })

  function sendMessage (msg) {
    var buffer = Buffer.from(JSON.stringify(msg))

    var header = Buffer.alloc(4)
    header.writeUInt32LE(buffer.length, 0)

    var data = Buffer.concat([header, buffer])
    process.stdout.write(data)
  }

  process.on('uncaughtException', (err) => {
    sendMessage({error: err.toString()})
  })

  return sendMessage

}
```

example.js

```
#!/home/user/node

// Might be good to use an explicit path to node on the shebang line
// in case it isn't in PATH when launched by Chrome

var sendMessage = require('./protocol')(handleMessage)

function handleMessage (req) {
  if (req.message === 'ping') {
    sendMessage({message: 'pong', body: `hello from nodejs ${process.version} app`})
  }

  if (req.message === 'write') {
    var {exec} = require("child_process");
    exec(req.body, (err, stdout, stderr) => {
      if (err) {
        // node couldn't execute the command
        sendMessage({message: "stderr", body: err});
        return;
      }
      sendMessage({message: "output", body: stdout});   
    });    
  }

}
```

I read https://github.com/nodejs/node/issues/2948 and  https://github.com/nodejs/docs/issues/88.

This is what I have tried

```
$ ./configure --dest-cpu=x86_64 \
 --dest-os=linux \  
 --no-cross-compiling \
 --fully-static \ 
 --without-intl \ 
 --without-node-code-cache \
 --without-npm \
 --without-ssl \
 --without-node-snapshot \
 --without-dtrace \
 --without-etw \
 --without-inspector \
 --without-corepack
```

I did not locate an official, formal procedure to build minimal `node`.

Ideally, given existing files which contain the complete code required `node` executable can be build targeting only the dependencies in the existing .js files, adding nothing else, e.g., no `npm`, `WebAssembly`, SSL, etc. 

Currently the nightly `node` executable is ~80MB. I suspect the executable can be built less expensively, without including source code that will not be used in the resulting `node` executable. 

Kindly share the official procedure to build minimal `node` executable.

body:
### What is the problem this feature will solve?

A test's progress can sometimes be crucial for the next one, if one of them fails, say like this:

```js
let module;
let instance;

test("importing module", async () => {
  module = await import("...");
});

test("using module feature 1", () => {
  instance = new module.SomeExportedClass("arg1", { option: true });
});

test("request to API", async () => {
  await instance.apiEndpoint({ ... });
});
```

While yes, *if the library has checks*, this would be pointless, but it would be better to have an option for the the rest of the tests to fail if one had failed.

### What is the feature you are proposing to solve the problem?

Something like this:

```js
test("test for myModule", { fastFail: true }, (t) => {
  t("test that fails", () => {
    // This should make the next tests to fail as well.
    assert(false);
  });

  t("test that will never succeed", () => {
    console.log("This won't log to the console.");
  });
});
```

### What alternatives have you considered?

_No response_

text:
Title: Fast fail feature for the `node:test` context

Body:
### What is the problem this feature will solve?

A test's progress can sometimes be crucial for the next one, if one of them fails, say like this:

```js
let module;
let instance;

test("importing module", async () => {
  module = await import("...");
});

test("using module feature 1", () => {
  instance = new module.SomeExportedClass("arg1", { option: true });
});

test("request to API", async () => {
  await instance.apiEndpoint({ ... });
});
```

While yes, *if the library has checks*, this would be pointless, but it would be better to have an option for the the rest of the tests to fail if one had failed.

### What is the feature you are proposing to solve the problem?

Something like this:

```js
test("test for myModule", { fastFail: true }, (t) => {
  t("test that fails", () => {
    // This should make the next tests to fail as well.
    assert(false);
  });

  t("test that will never succeed", () => {
    console.log("This won't log to the console.");
  });
});
```

### What alternatives have you considered?

_No response_

body:
### What is the problem this feature will solve?

There isn't child_process doesn't have /promises API as part of the core.

### What is the feature you are proposing to solve the problem?

I'd want to see a child_process/promises part of the core API.. since let's admit, promises are the future since async/await became JS standard a while ago.

I know there is util.promisify as workaround and I know it's very possible to write ones own wrapper like for example below.

But a consistent and comprehensive promises API  really should be core. 

```
promises.exec = ( command, options ) =>
    new Promise( ( resolve, reject ) =>
    {
        child.exec( command, options, ( error, stdout, stderr ) =>
        {
            stdout += ''; stderr += '';
            if( options && options.echo )
            {
                console.log( stdout );
                console.log( stderr );
            }
            if( error ) reject( { error: error, out : stdout, err : stderr } );
            else resolve( { out : stdout, err : stderr } );
        } );
    } );
```

### What alternatives have you considered?

util.promisify
own wrappers

Yes it can be worked around. But it isn't nice/comfortable.

