Title: Add `test.todo` to match `it.todo` in `node:test`

Body:
### What is the problem this feature will solve?

In the Node test runner (https://nodejs.org/api/test.html#test-runner) we have `describe.todo` and `it.todo` to designate suites/tests which do not exist yet but we're planning on adding. The `describe` > `it` syntax is one option of declaring tests, though, there is also just `test` in the API. For those of us who prefer `test` over `describe`, there is no shorthand `test.todo`, only the `test` method `todo` option: https://nodejs.org/api/test.html#testname-options-fn

### What is the feature you are proposing to solve the problem?

Add `test.todo` similarly to how `it.todo` currently exists:

```typescript
    namespace it {
        // Shorthand for skipping a test, same as `it([name], { skip: true }[, fn])`.
        function skip(name?: string, options?: TestOptions, fn?: ItFn): void;
        function skip(name?: string, fn?: ItFn): void;
        function skip(options?: TestOptions, fn?: ItFn): void;
        function skip(fn?: ItFn): void;

        // Shorthand for marking a test as `TODO`, same as `it([name], { todo: true }[, fn])`.
        function todo(name?: string, options?: TestOptions, fn?: ItFn): void;
        function todo(name?: string, fn?: ItFn): void;
        function todo(options?: TestOptions, fn?: ItFn): void;
        function todo(fn?: ItFn): void;
    }
```

### What alternatives have you considered?

Not doing it - we do have the `test` `todo` option so a shorthand is a QOL/DX improvement not a blocker of anything. I don't see the reason for why `it` should have it and `test` not though. Seems like parity on these would not hurt anything.

body:
### What is the problem this feature will solve?

When ESM loader resolve and load a virtual CJS module, named export not found.

### Reproduce Description

- use ESM loader to load a virtual CJS module

- the virtual CJS name is `virtual:reproduce`

- the virtual CJS code is `module.exports.foo = () => 42;`

- Expect: OK

- Actual: got `Named export 'foo' not found`

### Workaround

Add virtual ESM module using code `export const foo = CJSExports.foo`

But it will

- at least double the complexity of CJS part of `importHook.resolve`

- at least double the complexity of CJS part of `importHook.load`

So, I think better to introduce

```patch
-    return { format: 'commonjs', shortCircuit: true, source: undefined }
+    return { format: 'commonjs', shortCircuit: true, source: undefined, namedExports: ['foo'] }
```

### Reproduce

`reproduce.mjs`

```js
import { foo } from "virtual:reproduce";

// import mod from 'virtual:reproduce'
// const { foo } = mod

console.log({ foo })
```

`import-hook.mjs`

```js
const VIRTUAL_FILEURL = 'file:///virtual/reproduce'

export async function resolve(specifier, context, nextResolve) {
  if (specifier === 'virtual:reproduce') {
    return { format: 'commonjs', shortCircuit: true, url: VIRTUAL_FILEURL }
  }

  return await nextResolve(specifier, context)
}

export async function load(url, context, nextLoad) {
  if (url === VIRTUAL_FILEURL) {
    return { format: 'commonjs', shortCircuit: true, source: undefined }
  }

  return await nextLoad(url, context)
}
```

`require-hook.cjs`

```js
const { Module } = require('node:module')
// const { syncBuiltinESMExports } = require("node:module");
const $resolveFilename = Module._resolveFilename
const $handler = Module._extensions['.js']

const VIRTUAL_PATH = '/virtual/reproduce'
const VIRTUAL_CODE = `module.exports.foo = () => 42;`

Module._resolveFilename = function (request, parent, isMain, options) {
  if (request === VIRTUAL_PATH) {
    return VIRTUAL_PATH
  }

  return $resolveFilename(request, parent, isMain, options)
}

Module._extensions['.js'] = function (module, filename) {
  if (filename === VIRTUAL_PATH) {
    module._compile(VIRTUAL_CODE, filename)
    // syncBuiltinESMExports();
    return
  }

  $handler(module, filename)
}
```

### Actual

```sh
$ cd `mktemp -d`
$ tree
.
├── reproduce.mjs
├── import-hook.mjs
└── require-hook.cjs

1 directory, 3 files
$ node --require ./require-hook.cjs --loader ./import-hook.mjs ./reproduce.mjs 
(node:687343) ExperimentalWarning: Custom ESM Loaders is an experimental feature and might change at any time
(Use `node --trace-warnings ...` to show where the warning was created)
file:///path/to/reproduce.mjs:1
import { foo } from "virtual:reproduce";
         ^^^
SyntaxError: Named export 'foo' not found. The requested module 'virtual:reproduce' is a CommonJS module, which may not support all module.exports as named exports.
CommonJS modules can always be imported via the default export, for example using:

import pkg from 'virtual:reproduce';
const { foo } = pkg;

    at ModuleJob._instantiate (node:internal/modules/esm/module_job:124:21)
    at async ModuleJob.run (node:internal/modules/esm/module_job:190:5)

Node.js v18.15.0
```

### Expected

No error.

### What is the feature you are proposing to solve the problem?

Introduce `.namedExports` when format is `commonjs`

```patch
diff --git a/import-hook.mjs b/import-hook.mjs
index c454228..63b2d12 100644
--- a/import-hook.mjs
+++ b/import-hook.mjs
@@ -10,7 +10,7 @@ export async function resolve(specifier, context, nextResolve) {
 
 export async function load(url, context, nextLoad) {
   if (url === VIRTUAL_FILEURL) {
-    return { format: 'commonjs', shortCircuit: true, source: undefined }
+    return { format: 'commonjs', shortCircuit: true, source: undefined, namedExports: ['foo'] }
   }
 
   return await nextLoad(url, context)
```


### What alternatives have you considered?

_No response_

text:
Title: configure CJS named export within ESM loader

Body:
### What is the problem this feature will solve?

When ESM loader resolve and load a virtual CJS module, named export not found.

### Reproduce Description

- use ESM loader to load a virtual CJS module

- the virtual CJS name is `virtual:reproduce`

- the virtual CJS code is `module.exports.foo = () => 42;`

- Expect: OK

- Actual: got `Named export 'foo' not found`

### Workaround

Add virtual ESM module using code `export const foo = CJSExports.foo`

But it will

- at least double the complexity of CJS part of `importHook.resolve`

- at least double the complexity of CJS part of `importHook.load`

So, I think better to introduce

```patch
-    return { format: 'commonjs', shortCircuit: true, source: undefined }
+    return { format: 'commonjs', shortCircuit: true, source: undefined, namedExports: ['foo'] }
```

### Reproduce

`reproduce.mjs`

```js
import { foo } from "virtual:reproduce";

// import mod from 'virtual:reproduce'
// const { foo } = mod

console.log({ foo })
```

`import-hook.mjs`

```js
const VIRTUAL_FILEURL = 'file:///virtual/reproduce'

export async function resolve(specifier, context, nextResolve) {
  if (specifier === 'virtual:reproduce') {
    return { format: 'commonjs', shortCircuit: true, url: VIRTUAL_FILEURL }
  }

  return await nextResolve(specifier, context)
}

export async function load(url, context, nextLoad) {
  if (url === VIRTUAL_FILEURL) {
    return { format: 'commonjs', shortCircuit: true, source: undefined }
  }

  return await nextLoad(url, context)
}
```

`require-hook.cjs`

```js
const { Module } = require('node:module')
// const { syncBuiltinESMExports } = require("node:module");
const $resolveFilename = Module._resolveFilename
const $handler = Module._extensions['.js']

const VIRTUAL_PATH = '/virtual/reproduce'
const VIRTUAL_CODE = `module.exports.foo = () => 42;`

Module._resolveFilename = function (request, parent, isMain, options) {
  if (request === VIRTUAL_PATH) {
    return VIRTUAL_PATH
  }

  return $resolveFilename(request, parent, isMain, options)
}

Module._extensions['.js'] = function (module, filename) {
  if (filename === VIRTUAL_PATH) {
    module._compile(VIRTUAL_CODE, filename)
    // syncBuiltinESMExports();
    return
  }

  $handler(module, filename)
}
```

### Actual

```sh
$ cd `mktemp -d`
$ tree
.
├── reproduce.mjs
├── import-hook.mjs
└── require-hook.cjs

1 directory, 3 files
$ node --require ./require-hook.cjs --loader ./import-hook.mjs ./reproduce.mjs 
(node:687343) ExperimentalWarning: Custom ESM Loaders is an experimental feature and might change at any time
(Use `node --trace-warnings ...` to show where the warning was created)
file:///path/to/reproduce.mjs:1
import { foo } from "virtual:reproduce";
         ^^^
SyntaxError: Named export 'foo' not found. The requested module 'virtual:reproduce' is a CommonJS module, which may not support all module.exports as named exports.
CommonJS modules can always be imported via the default export, for example using:

import pkg from 'virtual:reproduce';
const { foo } = pkg;

    at ModuleJob._instantiate (node:internal/modules/esm/module_job:124:21)
    at async ModuleJob.run (node:internal/modules/esm/module_job:190:5)

Node.js v18.15.0
```

### Expected

No error.

### What is the feature you are proposing to solve the problem?

Introduce `.namedExports` when format is `commonjs`

```patch
diff --git a/import-hook.mjs b/import-hook.mjs
index c454228..63b2d12 100644
--- a/import-hook.mjs
+++ b/import-hook.mjs
@@ -10,7 +10,7 @@ export async function resolve(specifier, context, nextResolve) {
 
 export async function load(url, context, nextLoad) {
   if (url === VIRTUAL_FILEURL) {
-    return { format: 'commonjs', shortCircuit: true, source: undefined }
+    return { format: 'commonjs', shortCircuit: true, source: undefined, namedExports: ['foo'] }
   }
 
   return await nextLoad(url, context)
```


### What alternatives have you considered?

_No response_

